81: /**
82:  * An operator that implements the logic for windowing based on a {@link WindowAssigner} and {@link
83:  * Trigger}.
84:  *
85:  * <p>When an element arrives it gets assigned a key using a {@link KeySelector} and it gets
86:  * assigned to zero or more windows using a {@link WindowAssigner}. Based on this, the element is
87:  * put into panes. A pane is the bucket of elements that have the same key and same {@code Window}.
88:  * An element can be in multiple panes if it was assigned to multiple windows by the {@code
89:  * WindowAssigner}.
90:  *
91:  * <p>Each pane gets its own instance of the provided {@code Trigger}. This trigger determines when
92:  * the contents of the pane should be processed to emit results. When a trigger fires, the given
93:  * {@link InternalWindowFunction} is invoked to produce the results that are emitted for the pane to
94:  * which the {@code Trigger} belongs.
95:  *
96:  * @param <K> The type of key returned by the {@code KeySelector}.
97:  * @param <IN> The type of the incoming elements.
98:  * @param <OUT> The type of elements emitted by the {@code InternalWindowFunction}.
99:  * @param <W> The type of {@code Window} that the {@code WindowAssigner} assigns.
100:  */
101: @Internal
102: public class WindowOperator<K, IN, ACC, OUT, W extends Window>
103:         extends AbstractUdfStreamOperator<OUT, InternalWindowFunction<ACC, OUT, K, W>>
104:         implements OneInputStreamOperator<IN, OUT>, Triggerable<K, W> {
105: 
106:     private static final long serialVersionUID = 1L;
107: 
108:     // ------------------------------------------------------------------------
109:     // Configuration values and user functions
110:     // ------------------------------------------------------------------------
111: 
112:     protected final WindowAssigner<? super IN, W> windowAssigner;
113: 
114:     private final KeySelector<IN, K> keySelector;
115: 
116:     private final Trigger<? super IN, ? super W> trigger;
117: 
118:     private final StateDescriptor<? extends AppendingState<IN, ACC>, ?> windowStateDescriptor;
119: 
120:     /** For serializing the key in checkpoints. */
121:     protected final TypeSerializer<K> keySerializer;
122: 
123:     /** For serializing the window in checkpoints. */
124:     protected final TypeSerializer<W> windowSerializer;
125: 
126:     /**
127:      * The allowed lateness for elements. This is used for:
128:      *
129:      * <ul>
130:      *   <li>Deciding if an element should be dropped from a window due to lateness.
131:      *   <li>Clearing the state of a window if the system time passes the {@code window.maxTimestamp
132:      *       + allowedLateness} landmark.
133:      * </ul>
134:      */
135:     protected final long allowedLateness;
136: 
137:     /**
138:      * {@link OutputTag} to use for late arriving events. Elements for which {@code
139:      * window.maxTimestamp + allowedLateness} is smaller than the current watermark will be emitted
140:      * to this.
141:      */
142:     protected final OutputTag<IN> lateDataOutputTag;
143: 
144:     private static final String LATE_ELEMENTS_DROPPED_METRIC_NAME = "numLateRecordsDropped";
145: 
146:     protected transient Counter numLateRecordsDropped;
147: 
148:     // ------------------------------------------------------------------------
149:     // State that is not checkpointed
150:     // ------------------------------------------------------------------------
151: 
152:     /** The state in which the window contents is stored. Each window is a namespace */
153:     private transient InternalAppendingState<K, W, IN, ACC, ACC> windowState;
154: 
155:     /**
156:      * The {@link #windowState}, typed to merging state for merging windows. Null if the window
157:      * state is not mergeable.
158:      */
159:     private transient InternalMergingState<K, W, IN, ACC, ACC> windowMergingState;
160: 
161:     /** The state that holds the merging window metadata (the sets that describe what is merged). */
162:     private transient InternalListState<K, VoidNamespace, Tuple2<W, W>> mergingSetsState;
163: 
164:     /**
165:      * This is given to the {@code InternalWindowFunction} for emitting elements with a given
166:      * timestamp.
167:      */
168:     protected transient TimestampedCollector<OUT> timestampedCollector;
169: 
170:     protected transient Context triggerContext = new Context(null, null);
171: 
172:     protected transient WindowContext processContext;
173: 
174:     protected transient WindowAssigner.WindowAssignerContext windowAssignerContext;
175: 
176:     // ------------------------------------------------------------------------
177:     // State that needs to be checkpointed
178:     // ------------------------------------------------------------------------
179: 
180:     protected transient InternalTimerService<W> internalTimerService;
181: 
182:     /** Creates a new {@code WindowOperator} based on the given policies and user functions. */
183:     public WindowOperator(
184:             WindowAssigner<? super IN, W> windowAssigner,
185:             TypeSerializer<W> windowSerializer,
186:             KeySelector<IN, K> keySelector,
187:             TypeSerializer<K> keySerializer,
188:             StateDescriptor<? extends AppendingState<IN, ACC>, ?> windowStateDescriptor,
189:             InternalWindowFunction<ACC, OUT, K, W> windowFunction,
190:             Trigger<? super IN, ? super W> trigger,
191:             long allowedLateness,
192:             OutputTag<IN> lateDataOutputTag) {
193: 
194:         super(windowFunction);
195: 
196:         checkArgument(allowedLateness >= 0);
197: 
198:         checkArgument(
199:                 windowStateDescriptor == null || windowStateDescriptor.isSerializerInitialized(),
200:                 "window state serializer is not properly initialized");
201: 
202:         this.windowAssigner = checkNotNull(windowAssigner);
203:         this.windowSerializer = checkNotNull(windowSerializer);
204:         this.keySelector = checkNotNull(keySelector);
205:         this.keySerializer = checkNotNull(keySerializer);
206:         this.windowStateDescriptor = windowStateDescriptor;
207:         this.trigger = checkNotNull(trigger);
208:         this.allowedLateness = allowedLateness;
209:         this.lateDataOutputTag = lateDataOutputTag;
210:     }
211: 
212:     @Override
213:     public void setup(
214:             StreamTask<?, ?> containingTask,
215:             StreamConfig config,
216:             Output<StreamRecord<OUT>> output) {
217:         super.setup(containingTask, config, output);
218:     }
219: 
220:     @Override
221:     public void setProcessingTimeService(ProcessingTimeService processingTimeService) {
222:         super.setProcessingTimeService(processingTimeService);
223:     }
224: 
225:     @Override
226:     public void open() throws Exception {
227:         super.open();
228: 
229:         this.numLateRecordsDropped = metrics.counter(LATE_ELEMENTS_DROPPED_METRIC_NAME);
230:         timestampedCollector = new TimestampedCollector<>(output);
231: 
232:         internalTimerService = getInternalTimerService("window-timers", windowSerializer, this);
233: 
234:         triggerContext = new Context(null, null);
235:         processContext = new WindowContext(null);
236: 
237:         windowAssignerContext =
238:                 new WindowAssigner.WindowAssignerContext() {
239:                     @Override
240:                     public long getCurrentProcessingTime() {
241:                         return internalTimerService.currentProcessingTime();
242:                     }
243:                 };
244: 
245:         // create (or restore) the state that hold the actual window contents
246:         // NOTE - the state may be null in the case of the overriding evicting window operator
247:         if (windowStateDescriptor != null) {
248:             windowState =
249:                     (InternalAppendingState<K, W, IN, ACC, ACC>)
250:                             getOrCreateKeyedState(windowSerializer, windowStateDescriptor);
251:         }
252: 
253:         // create the typed and helper states for merging windows
254:         if (windowAssigner instanceof MergingWindowAssigner) {
255: 
256:             // store a typed reference for the state of merging windows - sanity check
257:             if (windowState instanceof InternalMergingState) {
258:                 windowMergingState = (InternalMergingState<K, W, IN, ACC, ACC>) windowState;
259:             } else if (windowState != null) {
260:                 throw new IllegalStateException(
261:                         "The window uses a merging assigner, but the window state is not mergeable.");
262:             }
263: 
264:             @SuppressWarnings("unchecked")
265:             final Class<Tuple2<W, W>> typedTuple = (Class<Tuple2<W, W>>) (Class<?>) Tuple2.class;
266: 
267:             final TupleSerializer<Tuple2<W, W>> tupleSerializer =
268:                     new TupleSerializer<>(
269:                             typedTuple, new TypeSerializer[] {windowSerializer, windowSerializer});
270: 
271:             final ListStateDescriptor<Tuple2<W, W>> mergingSetsStateDescriptor =
272:                     new ListStateDescriptor<>("merging-window-set", tupleSerializer);
273: 
274:             // get the state that stores the merging sets
275:             mergingSetsState =
276:                     (InternalListState<K, VoidNamespace, Tuple2<W, W>>)
277:                             getOrCreateKeyedState(
278:                                     VoidNamespaceSerializer.INSTANCE, mergingSetsStateDescriptor);
279:             mergingSetsState.setCurrentNamespace(VoidNamespace.INSTANCE);
280:         }
281:     }
282: 
283:     @Override
284:     public void close() throws Exception {
285:         super.close();
286:         timestampedCollector = null;
287:         triggerContext = null;
288:         processContext = null;
289:         windowAssignerContext = null;
290:     }
291: 
292:     @Override
293:     public void processElement(StreamRecord<IN> element) throws Exception {
294:         final Collection<W> elementWindows =
295:                 windowAssigner.assignWindows(
296:                         element.getValue(), element.getTimestamp(), windowAssignerContext);
297: 
298:         // if element is handled by none of assigned elementWindows
299:         boolean isSkippedElement = true;
300: 
301:         final K key = this.<K>getKeyedStateBackend().getCurrentKey();
302: 
303:         if (windowAssigner instanceof MergingWindowAssigner) {
304:             MergingWindowSet<W> mergingWindows = getMergingWindowSet();
305: 
306:             for (W window : elementWindows) {
307: 
308:                 // adding the new window might result in a merge, in that case the actualWindow
309:                 // is the merged window and we work with that. If we don't merge then
310:                 // actualWindow == window
311:                 W actualWindow =
312:                         mergingWindows.addWindow(
313:                                 window,
314:                                 new MergingWindowSet.MergeFunction<W>() {
315:                                     @Override
316:                                     public void merge(
317:                                             W mergeResult,
318:                                             Collection<W> mergedWindows,
319:                                             W stateWindowResult,
320:                                             Collection<W> mergedStateWindows)
321:                                             throws Exception {
322: 
323:                                         if ((windowAssigner.isEventTime()
324:                                                 && mergeResult.maxTimestamp() + allowedLateness
325:                                                         <= internalTimerService
326:                                                                 .currentWatermark())) {
327:                                             throw new UnsupportedOperationException(
328:                                                     "The end timestamp of an "
329:                                                             + "event-time window cannot become earlier than the current watermark "
330:                                                             + "by merging. Current watermark: "
331:                                                             + internalTimerService
332:                                                                     .currentWatermark()
333:                                                             + " window: "
334:                                                             + mergeResult);
335:                                         } else if (!windowAssigner.isEventTime()) {
336:                                             long currentProcessingTime =
337:                                                     internalTimerService.currentProcessingTime();
338:                                             if (mergeResult.maxTimestamp()
339:                                                     <= currentProcessingTime) {
340:                                                 throw new UnsupportedOperationException(
341:                                                         "The end timestamp of a "
342:                                                                 + "processing-time window cannot become earlier than the current processing time "
343:                                                                 + "by merging. Current processing time: "
344:                                                                 + currentProcessingTime
345:                                                                 + " window: "
346:                                                                 + mergeResult);
347:                                             }
348:                                         }
349: 
350:                                         triggerContext.key = key;
351:                                         triggerContext.window = mergeResult;
352: 
353:                                         triggerContext.onMerge(mergedWindows);
354: 
355:                                         for (W m : mergedWindows) {
356:                                             triggerContext.window = m;
357:                                             triggerContext.clear();
358:                                             deleteCleanupTimer(m);
359:                                         }
360: 
361:                                         // merge the merged state windows into the newly resulting
362:                                         // state window
363:                                         windowMergingState.mergeNamespaces(
364:                                                 stateWindowResult, mergedStateWindows);
365:                                     }
366:                                 });
367: 
368:                 // drop if the window is already late
369:                 if (isWindowLate(actualWindow)) {
370:                     mergingWindows.retireWindow(actualWindow);
371:                     continue;
372:                 }
373:                 isSkippedElement = false;
374: 
375:                 W stateWindow = mergingWindows.getStateWindow(actualWindow);
376:                 if (stateWindow == null) {
377:                     throw new IllegalStateException(
378:                             "Window " + window + " is not in in-flight window set.");
379:                 }
380: 
381:                 windowState.setCurrentNamespace(stateWindow);
382:                 windowState.add(element.getValue());
383: 
384:                 triggerContext.key = key;
385:                 triggerContext.window = actualWindow;
386: 
387:                 TriggerResult triggerResult = triggerContext.onElement(element);
388: 
389:                 if (triggerResult.isFire()) {
390:                     ACC contents = windowState.get();
391:                     if (contents != null) {
392:                         emitWindowContents(actualWindow, contents);
393:                     }
394:                 }
395: 
396:                 if (triggerResult.isPurge()) {
397:                     windowState.clear();
398:                 }
399:                 registerCleanupTimer(actualWindow);
400:             }
401: 
402:             // need to make sure to update the merging state in state
403:             mergingWindows.persist();
404:         } else {
405:             for (W window : elementWindows) {
406: 
407:                 // drop if the window is already late
408:                 if (isWindowLate(window)) {
409:                     continue;
410:                 }
411:                 isSkippedElement = false;
412: 
413:                 windowState.setCurrentNamespace(window);
414:                 windowState.add(element.getValue());
415: 
416:                 triggerContext.key = key;
417:                 triggerContext.window = window;
418: 
419:                 TriggerResult triggerResult = triggerContext.onElement(element);
420: 
421:                 if (triggerResult.isFire()) {
422:                     ACC contents = windowState.get();
423:                     if (contents != null) {
424:                         emitWindowContents(window, contents);
425:                     }
426:                 }
427: 
428:                 if (triggerResult.isPurge()) {
429:                     windowState.clear();
430:                 }
431:                 registerCleanupTimer(window);
432:             }
433:         }
434: 
435:         // side output input event if
436:         // element not handled by any window
437:         // late arriving tag has been set
438:         // windowAssigner is event time and current timestamp + allowed lateness no less than
439:         // element timestamp
440:         if (isSkippedElement && isElementLate(element)) {
441:             if (lateDataOutputTag != null) {
442:                 sideOutput(element);
443:             } else {
444:                 this.numLateRecordsDropped.inc();
445:             }
446:         }
447:     }
448: 
449:     @Override
450:     public void onEventTime(InternalTimer<K, W> timer) throws Exception {
451:         triggerContext.key = timer.getKey();
452:         triggerContext.window = timer.getNamespace();
453: 
454:         MergingWindowSet<W> mergingWindows;
455: 
456:         if (windowAssigner instanceof MergingWindowAssigner) {
457:             mergingWindows = getMergingWindowSet();
458:             W stateWindow = mergingWindows.getStateWindow(triggerContext.window);
459:             if (stateWindow == null) {
460:                 // Timer firing for non-existent window, this can only happen if a
461:                 // trigger did not clean up timers. We have already cleared the merging
462:                 // window and therefore the Trigger state, however, so nothing to do.
463:                 return;
464:             } else {
465:                 windowState.setCurrentNamespace(stateWindow);
466:             }
467:         } else {
468:             windowState.setCurrentNamespace(triggerContext.window);
469:             mergingWindows = null;
470:         }
471: 
472:         TriggerResult triggerResult = triggerContext.onEventTime(timer.getTimestamp());
473: 
474:         if (triggerResult.isFire()) {
475:             ACC contents = windowState.get();
476:             if (contents != null) {
477:                 emitWindowContents(triggerContext.window, contents);
478:             }
479:         }
480: 
481:         if (triggerResult.isPurge()) {
482:             windowState.clear();
483:         }
484: 
485:         if (windowAssigner.isEventTime()
486:                 && isCleanupTime(triggerContext.window, timer.getTimestamp())) {
487:             clearAllState(triggerContext.window, windowState, mergingWindows);
488:         }
489: 
490:         if (mergingWindows != null) {
491:             // need to make sure to update the merging state in state
492:             mergingWindows.persist();
493:         }
494:     }
495: 
496:     @Override
497:     public void onProcessingTime(InternalTimer<K, W> timer) throws Exception {
498:         triggerContext.key = timer.getKey();
499:         triggerContext.window = timer.getNamespace();
500: 
501:         MergingWindowSet<W> mergingWindows;
502: 
503:         if (windowAssigner instanceof MergingWindowAssigner) {
504:             mergingWindows = getMergingWindowSet();
505:             W stateWindow = mergingWindows.getStateWindow(triggerContext.window);
506:             if (stateWindow == null) {
507:                 // Timer firing for non-existent window, this can only happen if a
508:                 // trigger did not clean up timers. We have already cleared the merging
509:                 // window and therefore the Trigger state, however, so nothing to do.
510:                 return;
511:             } else {
512:                 windowState.setCurrentNamespace(stateWindow);
513:             }
514:         } else {
515:             windowState.setCurrentNamespace(triggerContext.window);
516:             mergingWindows = null;
517:         }
518: 
519:         TriggerResult triggerResult = triggerContext.onProcessingTime(timer.getTimestamp());
520: 
521:         if (triggerResult.isFire()) {
522:             ACC contents = windowState.get();
523:             if (contents != null) {
524:                 emitWindowContents(triggerContext.window, contents);
525:             }
526:         }
527: 
528:         if (triggerResult.isPurge()) {
529:             windowState.clear();
530:         }
531: 
532:         if (!windowAssigner.isEventTime()
533:                 && isCleanupTime(triggerContext.window, timer.getTimestamp())) {
534:             clearAllState(triggerContext.window, windowState, mergingWindows);
535:         }
536: 
537:         if (mergingWindows != null) {
538:             // need to make sure to update the merging state in state
539:             mergingWindows.persist();
540:         }
541:     }
542: 
543:     @Override
544:     public OperatorAttributes getOperatorAttributes() {
545:         boolean isOutputOnlyAfterEndOfStream =
546:                 windowAssigner instanceof GlobalWindows
547:                         && trigger instanceof GlobalWindows.EndOfStreamTrigger;
548:         return new OperatorAttributesBuilder()
549:                 .setOutputOnlyAfterEndOfStream(isOutputOnlyAfterEndOfStream)
550:                 .build();
551:     }
552: 
553:     /**
554:      * Drops all state for the given window and calls {@link Trigger#clear(Window,
555:      * Trigger.TriggerContext)}.
556:      *
557:      * <p>The caller must ensure that the correct key is set in the state backend and the
558:      * triggerContext object.
559:      */
560:     private void clearAllState(
561:             W window, AppendingState<IN, ACC> windowState, MergingWindowSet<W> mergingWindows)
562:             throws Exception {
563:         windowState.clear();
564:         triggerContext.clear();
565:         processContext.window = window;
566:         processContext.clear();
567:         if (mergingWindows != null) {
568:             mergingWindows.retireWindow(window);
569:             mergingWindows.persist();
570:         }
571:     }
572: 
573:     /** Emits the contents of the given window using the {@link InternalWindowFunction}. */
574:     @SuppressWarnings("unchecked")
575:     private void emitWindowContents(W window, ACC contents) throws Exception {
576:         timestampedCollector.setAbsoluteTimestamp(window.maxTimestamp());
577:         processContext.window = window;
578:         userFunction.process(
579:                 triggerContext.key, window, processContext, contents, timestampedCollector);
580:     }
581: 
582:     /**
583:      * Write skipped late arriving element to SideOutput.
584:      *
585:      * @param element skipped late arriving element to side output
586:      */
587:     protected void sideOutput(StreamRecord<IN> element) {
588:         output.collect(lateDataOutputTag, element);
589:     }
590: 
591:     /**
592:      * Retrieves the {@link MergingWindowSet} for the currently active key. The caller must ensure
593:      * that the correct key is set in the state backend.
594:      *
595:      * <p>The caller must also ensure to properly persist changes to state using {@link
596:      * MergingWindowSet#persist()}.
597:      */
598:     protected MergingWindowSet<W> getMergingWindowSet() throws Exception {
599:         @SuppressWarnings("unchecked")
600:         MergingWindowAssigner<? super IN, W> mergingAssigner =
601:                 (MergingWindowAssigner<? super IN, W>) windowAssigner;
602:         return new MergingWindowSet<>(mergingAssigner, mergingSetsState);
603:     }
604: 
605:     /**
606:      * Returns {@code true} if the watermark is after the end timestamp plus the allowed lateness of
607:      * the given window.
608:      */
609:     protected boolean isWindowLate(W window) {
610:         return (windowAssigner.isEventTime()
611:                 && (cleanupTime(window) <= internalTimerService.currentWatermark()));
612:     }
613: 
614:     /**
615:      * Decide if a record is currently late, based on current watermark and allowed lateness.
616:      *
617:      * @param element The element to check
618:      * @return The element for which should be considered when sideoutputs
619:      */
620:     protected boolean isElementLate(StreamRecord<IN> element) {
