                (InternalListState<K, W, StreamRecord<IN>>)
                        getOrCreateKeyedState(windowSerializer, streamRecordStateDescriptor);

        evictorContext = new EvictorContext(null, null);
    }

    private TypeSerializer<StreamRecord<IN>> streamRecordSerializer;

    @Override
    public void setStreamRecordSerializer(TypeSerializer<StreamRecord<IN>> streamRecordSerializer) {
        super.setStreamRecordSerializer(streamRecordSerializer);
        this.streamRecordSerializer = streamRecordSerializer;
    }

    /**
     * Evictor can evict elements from pane before and after the window function is applied
     */
    public class EvictorContext implements Evictor.EvictContext {
        private K key;
        private W window;

        public EvictorContext(K key, W window) {
            this.key = key;
            this.window = window;
        }

        @Override
        public long getCurrentProcessingTime() {
            return internalTimerService.currentProcessingTime();
        }

        @Override
        public MetricGroup getMetricGroup() {
            return EvictingWindowOperator.this.getMetricGroup();
        }

        public long getCurrentWatermark() {
            return internalTimerService.currentWatermark();
        }

        public void evictBefore(
                Iterable<IN> elements, AppendingState<IN, Iterable<IN>> state) throws Exception {
            evictorContext.window = window;
            evictorContext.key = key;
            evictor.evictBefore(elements, state, evictorContext);
        }

        public void evictAfter(
                Iterable<StreamRecord<IN>> elements,
                AppendingState<IN, Iterable<IN>> state)
                throws Exception {
            evictorContext.window = window;
            evictorContext.key = key;
            evictor.evictAfter(elements, state, evictorContext);
        }

        @Override
        public String toString() {
            return "EvictorContext{" + "key=" + key + ", window=" + window + '}';
        }
    }
